let schemaPromise;
function json(data, init = {}) { const headers = new Headers(init.headers || {}); headers.set('content-type','application/json; charset=utf-8'); headers.set('cache-control',headers.get('cache-control')||'no-store'); return new Response(JSON.stringify(data),{...init,headers}); }
function error(message,status=400){return json({ok:false,error:message},{status});}
function cleanText(value,fallback=''){return typeof value==='string'?value.trim().slice(0,5000):fallback;}
function nullableNumber(value){if(value===''||value===null||value===undefined)return null;const number=Number(value);return Number.isFinite(number)&&number>=0?Math.round(number):null;}
function safeBool(value, fallback=false){return value===true||value==='true'||value==='on'||value===1||value==='1'?true:fallback;}
function slugify(value){return String(value||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'').slice(0,100)||`xe-${Date.now()}`;}
function parseImages(value){try{const data=Array.isArray(value)?value:JSON.parse(value||'[]');return Array.isArray(data)?data.filter(item=>typeof item==='string'&&item.length<1000).slice(0,12):[];}catch{return [];}}
function parseColorVariants(value){
  try{const data=Array.isArray(value)?value:JSON.parse(value||'[]'); if(!Array.isArray(data))return []; return data.map(item=>{const name=cleanText(item?.name).slice(0,80);const hex=/^#[0-9a-f]{6}$/i.test(String(item?.hex||''))?String(item.hex).toLowerCase():'#7a7a7a';const legacy=item?.image||item?.image_url||'';const images=[...new Set((Array.isArray(item?.images)?item.images:(legacy?[legacy]:[])).map(image=>cleanText(image).slice(0,1000)).filter(Boolean))].slice(0,12);return {name,hex,images};}).filter(item=>item.name&&item.images.length).slice(0,20);}catch{return [];}
}
function rowToBike(row){const images=parseImages(row.images);let color_variants=parseColorVariants(row.color_variants);if(!color_variants.length&&row.color&&images[0])color_variants=[{name:String(row.color).split(',')[0].trim()||'Màu sẵn có',hex:'#7a7a7a',images:[images[0]]}];return {...row,images,color_variants,featured:Boolean(row.featured),show_price:row.show_price===null||row.show_price===undefined?true:Boolean(row.show_price),installment_from:Number(row.installment_from||0),bad_debt_down_payment:Number(row.bad_debt_down_payment||0)};}
function rowToPromotion(row){return {...row,active:Boolean(row.active)};}
function rowToAccessory(row){return {...row,active:Boolean(row.active)};}
function rowToPolicy(row){return {...row,active:Boolean(row.active)};}
function normalizePolicy(payload={}){const title=cleanText(payload.title);return {slug:slugify(payload.slug||title),title,excerpt:cleanText(payload.excerpt),content:cleanText(payload.content),active:safeBool(payload.active)?1:0,sort_order:nullableNumber(payload.sort_order)||0};}
function cookies(request){return Object.fromEntries((request.headers.get('cookie')||'').split(';').map(item=>item.trim().split('=').map(decodeURIComponent)).filter(([key])=>key));}
function base64Url(bytes){let string='';for(const byte of bytes)string+=String.fromCharCode(byte);return btoa(string).replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/g,'');}
async function sign(value,secret){const key=await crypto.subtle.importKey('raw',encoder.encode(secret||''),{name:'HMAC',hash:'SHA-256'},false,['sign']);return base64Url(new Uint8Array(await crypto.subtle.sign('HMAC',key,encoder.encode(value))));}
async function createSession(secret,payload){const token=base64Url(encoder.encode(JSON.stringify({...payload,exp:Date.now()+12*60*60*1000})));return `${token}.${await sign(token,secret)}`;}
async function getSession(request,env){const token=cookies(request).tam_an_admin;if(!token||!env.SESSION_SECRET)return null;const [payload,signature]=token.split('.');if(!payload||!signature||signature!==await sign(payload,env.SESSION_SECRET))return null;try{const decoded=atob(payload.replace(/-/g,'+').replace(/_/g,'/').padEnd(Math.ceil(payload.length/4)*4,'='));const session=JSON.parse(new TextDecoder().decode(Uint8Array.from(decoded,c=>c.charCodeAt(0))));return session.exp>Date.now()?session:null;}catch{return null;}}
async function passwordHash(password,secret){const bytes=await crypto.subtle.digest('SHA-256',encoder.encode(`${secret}|tam-an-staff|${password}`));return [...new Uint8Array(bytes)].map(x=>x.toString(16).padStart(2,'0')).join('');}
async function parseJson(request){try{return await request.json();}catch{return null;}}
function hasRole(session,role){return Boolean(session?.role===role);}
async function requireSession(request,env){const session=await getSession(request,env);return session||null;}
async function addColumn(env,table,column,definition){try{const result=await env.DB.prepare(`PRAGMA table_info(${table})`).all();if(!(result.results||[]).some(item=>item.name===column))await env.DB.prepare(`ALTER TABLE ${table} ADD COLUMN ${column} ${definition}`).run();}catch(cause){if(!String(cause?.message||cause).toLowerCase().includes('duplicate column'))throw cause;}}
