  if(bikeMatch&&request.method==='DELETE'){if(session.role!=='owner')return error('Nhân viên không có quyền xoá xe.',403);const bike=await env.DB.prepare('SELECT name FROM bikes WHERE id=?').bind(Number(bikeMatch[1])).first();await env.DB.prepare('DELETE FROM bikes WHERE id=?').bind(Number(bikeMatch[1])).run();await writeSystemLog(env,session,'inventory.deleted','bike',bikeMatch[1],bike?.name||'');return json({ok:true});}
  if(path==='/api/admin/leads'&&request.method==='GET'){
    const terms=[],values=[],status=url.searchParams.get('status'),staffId=Number(url.searchParams.get('staff_id')||0);
    if(WORK_STATUS.has(status)){terms.push('l.status=?');values.push(status);} if(staffId){terms.push('l.assigned_staff_id=?');values.push(staffId);} filterDateClause('l.created_at',url.searchParams.get('date_from'),'>=',terms,values);filterDateClause('l.created_at',url.searchParams.get('date_to'),'<=',terms,values);
    const sql=`SELECT l.* FROM leads l ${terms.length?`WHERE ${terms.join(' AND ')}`:''} ORDER BY CASE l.status WHEN 'new' THEN 0 WHEN 'processing' THEN 1 ELSE 2 END,l.created_at DESC LIMIT 500`;
    const result=values.length?await env.DB.prepare(sql).bind(...values).all():await env.DB.prepare(sql).all();return json({ok:true,leads:result.results||[]});
  }
