export default { async fetch(request,env){const url=new URL(request.url);if(url.pathname.startsWith('/api/')||url.pathname.startsWith('/media/')){try{return await handleApi(request,env,url);}catch(cause){console.error(cause);return error('Máy chủ tạm thời gặp lỗi.',500);}}return env.ASSETS.fetch(request);} };
